import asyncio

async def fetch(url: str) -> str:
    await asyncio.sleep(5)  # pretend this is an HTTP call
    return f"response from {url}"

async def fetch_with_retry(url: str, timeout: float, retries: int) -> str:
    for attempt in range(1, retries + 1):
        try:
            return await asyncio.wait_for(fetch(url), timeout=timeout)
        except asyncio.TimeoutError:
            print(f"Attempt {attempt} timed out")
    raise RuntimeError("All attempts exhausted")

asyncio.run(fetch_with_retry("https://example.com", timeout=2.0, retries=3))
